from flask import g
import sqlite3

def get_user_by_email(email):
    # Connect to the database (this should be configured once, not on every call)
    db = get_db()

    # Query the user by email
    user = db.execute(
        'SELECT * FROM users WHERE email = ?',
        (email,)
    ).fetchone()

    # Return the user as a dictionary or None if not found
    return dict(user) if user else None

def get_db():
    if 'db' not in g:
        g.db = sqlite3.connect('your_database.db')
        g.db.row_factory = sqlite3.Row  # Allows fetching rows as dictionaries
    return g.db

@app.teardown_appcontext
def close_db(exception):
    db = g.pop('db', None)
    if db is not None:
        db.close()

@app.route('/login', methods=['POST'])
def login():
    email = request.json.get('email')
    user = get_user_by_email(email)
    if user:
        return jsonify({'message': 'User found', 'user': user})
    else:
        return jsonify({'message': 'User not found'}), 404

