// Customer represents a customer record from the database.
type Customer struct {
	ID           int
	Name         string
	City         string
	Status       string
	SignupYear   int
	// Add other fields as needed
}

// FindCustomers queries the customers table with optional filters.
func FindCustomers(db *sql.DB, filters map[string]string) ([]Customer, error) {
	// Base SQL query
	query := "SELECT id, name, city, status, signup_year FROM customers"
	args := []interface{}{}

	// Build WHERE clause dynamically
	whereClauses := []string{}
	for key, value := range filters {
		switch key {
		case "status":
			whereClauses = append(whereClauses, fmt.Sprintf("status = ?"))
			args = append(args, value)
		case "city":
			whereClauses = append(whereClauses, fmt.Sprintf("city = ?"))
			args = append(args, value)
		case "signup_year":
			// Convert string to integer
			year, err := fmt.Atoi(value)
			if err != nil {
				return nil, fmt.Errorf("invalid signup_year: %w", err)
			}
			whereClauses = append(whereClauses, fmt.Sprintf("signup_year = ?"))
			args = append(args, year)
		}
	}

	// Append WHERE clause if any filters are present
	if len(whereClauses) > 0 {
		query += " WHERE " + strings.Join(whereClauses, " AND ")
	}

	// Execute query
	rows, err := db.Query(query, args...)
	if err != nil {
		return nil, err
	}
	defer rows.Close()

	var customers []Customer
	for rows.Next() {
		var c Customer
		err := rows.Scan(&c.ID, &c.Name, &c.City, &c.Status, &c.SignupYear)
		if err != nil {
			return nil, err
		}
