func QueryCustomers(db *sql.DB, filters map[string]interface{}) ([]Customer, error) {
    var (
        args     []interface{}
        clauses  []string
        query    strings.Builder
    )

    // Base query
    query.WriteString("SELECT id, name, status, city, signup_year FROM customers")

    // Build WHERE clause dynamically
    if len(filters) > 0 {
        query.WriteString(" WHERE ")
        clauses = make([]string, 0, len(filters))
        args = make([]interface{}, 0, len(filters))

        for key, value := range filters {
            switch key {
            case "status":
                clauses = append(clauses, "status = ?")
                args = append(args, value)
            case "city":
                clauses = append(clauses, "city = ?")
                args = append(args, value)
            case "signup_year":
                clauses = append(clauses, "signup_year = ?")
                args = append(args, value)
            }
        }

        query.WriteString(strings.Join(clauses, " AND "))
    }

    // Execute query
    rows, err := db.Query(query.String(), args...)
    if err != nil {
        return nil, err
    }
    defer rows.Close()

    var customers []Customer
    for rows.Next() {
        var c Customer
        if err := rows.Scan(&c.ID, &c.Name, &c.Status, &c.City, &c.SignupYear); err != nil {
