```go
package main

import (
	"database/sql"
	"fmt"
	"strings"
)

// Order represents an order from the database.
type Order struct {
	ID    int
	Name  string
	Total float64
	// Add other fields as needed
}

// GetOrdersByIDs retrieves orders by their IDs using a single query with an IN clause.
func GetOrdersByIDs(db *sql.DB, orderIDs []int) ([]Order, error) {
	if len(orderIDs) == 0 {
		return []Order{}, nil
	}

	// Create a placeholder string for the IN clause
	placeholders := make([]string, len(orderIDs))
	for i := range orderIDs {
		placeholders[i] = "?"
	}
	inClause := strings.Join(placeholders, ", ")

	// Query the database
	query := fmt.Sprintf("SELECT id, name, total FROM orders WHERE id IN (%s)", inClause)
	rows, err := db.Query(query, orderIDs...)
	if err != nil {
		return nil, err
	}
	defer rows.Close()

	var orders []Order
	for rows.Next() {
		var order Order
		if err := rows.Scan(&order.ID, &order.Name, &order.Total); err != nil {
			return nil, err
		}
		orders = append(orders, order)
	}

	if err := rows.Err(); err != nil {
		return nil, err
	}

	return orders, nil
}
```

### Notes:

- This function assumes the `orders` table has columns `id`, `name`, and `total`. Adjust the `Scan` call and the SQL query accordingly if your schema is different.
- It uses `?` placeholders for parameterized queries to prevent SQL injection.
- If `orderIDs` is empty, it returns an empty slice and `nil` error.
- The `IN` clause is dynamically built based on the length of `orderIDs`.

