package main

import (
    "database/sql"
    "fmt"
    "log"
    "net/http"
)

// Product represents a product in the database
type Product struct {
    ID        int
    Name      string
    Price     float64
    CreatedAt string
}

// GetProducts retrieves all products sorted by the specified column
func GetProducts(db *sql.DB, sortColumn string) ([]Product, error) {
    var products []Product

    // Valid sort columns
    validColumns := map[string]bool{
        "name":       true,
        "price":      true,
        "created_at": true,
    }

    // Check if the sort column is valid
    if !validColumns[sortColumn] {
        return nil, fmt.Errorf("invalid sort column: %s", sortColumn)
    }

    // Build the SQL query dynamically
    query := fmt.Sprintf("SELECT id, name, price, created_at FROM products ORDER BY %s", sortColumn)

    // Execute the query
    rows, err := db.Query(query)
    if err != nil {
        return nil, err
    }
    defer rows.Close()

    // Scan the results into Product structs
    for rows.Next() {
        var p Product
        if err := rows.Scan(&p.ID, &p.Name, &p.Price, &p.CreatedAt); err != nil {
            return nil, err
        }
        products = append(products, p)
    }

    if err := rows.Err(); err != nil {
        return nil, err
    }

    return products, nil
}

