```go
package main

import (
	"database/sql"
	"fmt"
	_ "github.com/go-sql-driver/mysql" // or other driver
)

// Product represents a product in the database
type Product struct {
	ID   int
	Name string
	// Add other fields as needed
}

// SearchProducts searches for products whose name contains the given term
func SearchProducts(db *sql.DB, term string) ([]Product, error) {
	query := "SELECT id, name FROM products WHERE LOWER(name) LIKE LOWER(?)"
	rows, err := db.Query(query, "%"+term+"%")
	if err != nil {
		return nil, fmt.Errorf("failed to query products: %w", err)
	}
	defer rows.Close()

	var products []Product
	for rows.Next() {
		var p Product
		if err := rows.Scan(&p.ID, &p.Name); err != nil {
			return nil, fmt.Errorf("failed to scan row: %w", err)
		}
		products = append(products, p)
	}

	if err := rows.Err(); err != nil {
		return nil, fmt.Errorf("error during iteration: %w", err)
	}

	return products, nil
}
```

### Notes:

- **Database Driver**: The `_ "github.com/go-sql-driver/mysql"` line is just an example. You should replace it with the appropriate driver for your database (e.g., `github.com/lib/pq` for PostgreSQL).
- **Case-Insensitive Search**: The `LOWER(name) LIKE LOWER(?)` ensures the search is case-insensitive.
- **Wildcard Usage**: `%` is used on both sides of the search term to match any substring.
- **Error Handling**: Errors are wrapped with `fmt.Errorf` and returned with `%w` to preserve the original error context.

### Example Usage:

