use sqlx::postgres::PgPool;
use sqlx::types::Uuid;
use sqlx::Error;
use std::collections::HashMap;

pub async fn find_customers(
    pool: &PgPool,
    filters: &HashMap<String, String>,
) -> Result<Vec<uuid::Uuid>, Error> {
    let mut query = String::from("SELECT id FROM customers");

    let mut params = Vec::new();
    let mut first = true;

    for (key, value) in filters {
        match key.as_str() {
            "status" | "city" | "signup_year" => {
                if !first {
                    query.push(' ');
                    query.push_str("AND");
                    query.push(' ');
                }

                query.push_str(&format!("{} = ${}", key, params.len() + 1));
                params.push(value.clone());
                first = false;
            }
            _ => {
                // Ignore unknown filter keys
            }
        }
    }

    let mut rows = sqlx::query(&query)
        .bind_params(&params)
        .fetch_all(pool)
        .await?;

    let ids: Vec<uuid::Uuid> = rows
        .into_iter()
        .map(|row| row.get::<Uuid, _>("id"))
        .collect();

    Ok(ids)
}
```

### Notes:

- This function returns a `Vec<uuid::Uuid>` representing the `id`s of the customers that match the filters.
- It uses `sqlx::query` with dynamic SQL construction based on the keys in the `filters` map.
- Only the keys `"status"`, `"city"`, and `"signup_year"` are used for filtering.
- If the `filters` map is empty, it returns all customers.
- The `params` vector is used to bind values safely to prevent SQL injection.
- The `uuid::Uuid` type is used for the customer ID — make sure you have the `uuid` crate in your dependencies.

### Example usage:

```rust
