    "SELECT * FROM customers {}",
    if where_clauses.is_empty() {
        String::new()
    } else {
        format!("WHERE {}", where_clauses.join(" AND "))
    }
);

let rows = sqlx::query(&query)
    .bind(params[0])
    .bind(params[1])
    // ... and so on
    .fetch_all(pool)
    .await?;
```

