    let conn = Connection::open(Path::new(db_path))?;

    let mut stmt = conn.prepare("SELECT id, name FROM users WHERE id = ?")?;
    let mut rows = stmt.query &[user_id])?;

    if let Some(row) = rows.next()? {
        Ok(Some(User {
            id: row.get(0)?,
            name: row.get(1)?,
        }))
    } else {
        Ok(None)
    }
}
