use rusqlite::{Connection, Result};
use std::vec::Vec;

pub fn get_orders_by_ids(conn: &Connection, order_ids: &[i64]) -> Result<Vec<(i64, String, i64)>> {
    if order_ids.is_empty() {
        return Ok(vec![]);
    }

    let mut stmt = conn.prepare("SELECT id, customer_name, total_amount FROM orders WHERE id IN ($1)")?;
    let mut params = Vec::new();

    // Create a comma-separated string of the order IDs
    let ids_str: Vec<String> = order_ids.iter().map(|id| id.to_string()).collect();
    let ids_str = ids_str.join(",");

    // Bind the parameter
    stmt.bind_text(1, &ids_str)?;

    let mut rows = stmt.query([])?;
    let mut orders = Vec::new();

    while let Some(row) = rows.next()? {
        let id: i64 = row.get(0)?;
        let customer_name: String = row.get(1)?;
        let total_amount: i64 = row.get(2)?;
        orders.push((id, customer_name, total_amount));
    }

    Ok(orders)
}
