```rust
use rusqlite::{Connection, Result};
use std::vec::Vec;

pub fn get_orders_by_ids(conn: &Connection, order_ids: &[i64]) -> Result<Vec<(i64, String, i64)>> {
    if order_ids.is_empty() {
        return Ok(vec![]);
    }

    let mut stmt = conn.prepare("SELECT id, customer_name, total_amount FROM orders WHERE id IN (")?;
    let mut query = String::new();

    // Build the IN clause
    for (i, &id) in order_ids.iter().enumerate() {
        if i > 0 {
            query.push(',');
        }
        query.push_str(&id.to_string());
    }

    query.push(')');

    // Append the query to the prepared statement
    let full_query = format!("{}{}", stmt.sql(), query);
    let stmt = conn.prepare(&full_query)?;

    let mut rows = stmt.query_map([], |row| {
        Ok((
            row.get(0)?,
            row.get(1)?,
            row.get(2)?,
        ))
    })?;

    let mut orders = Vec::new();
    for row in &mut rows {
        orders.push(row?);
    }

    Ok(orders)
}
```

