pub fn get_orders_by_ids(conn: &Connection, ids: &[i64]) -> Result<Vec<Order>> {
    if ids.is_empty() {
        return Ok(vec![]);
    }

    let mut stmt: Statement = conn.prepare("SELECT id, customer_name, total_amount FROM orders WHERE id IN ($ids)")?;
    let mut params = Vec::new();

    // Create a parameter placeholder string like (?, ?, ?)
    let placeholders: String = ids.iter().map(|_| "?").collect::<Vec<_>>().join(", ");
    let query = format!("SELECT id, customer_name, total_amount FROM orders WHERE id IN ({})", placeholders);

    // Re-prepare the statement with the correct number of placeholders
    let mut stmt = conn.prepare(&query)?;
    for id in ids {
        stmt.bind_parameter(0, *id)?;
    }

    let mut rows = stmt.query([])?;
    let mut orders = Vec::new();

    while let Some(row) = rows.next()? {
        let id: i64 = row.get(0)?;
        let customer_name: String = row.get(1)?;
        let total_amount: f64 = row.get(2)?;

        orders.push(Order {
            id,
            customer_name,
            total_amount,
        });
    }

    Ok(orders)
}

