```rust
use std::collections::HashMap;
use rusqlite::{Connection, Result, Statement};

pub fn create_user_from_form(
    conn: &Connection,
    form: &HashMap<String, String>,
) -> Result<i64> {
    // Assume the users table has columns: id INTEGER PRIMARY KEY, name TEXT, email TEXT
    let mut stmt = conn.prepare("INSERT INTO users (name, email) VALUES (?, ?)")?;

    // Extract name and email from the form
    let name = form.get("name").ok_or(rusqlite::Error::InvalidParameter)?;
    let email = form.get("email").ok_or(rusqlite::Error::InvalidParameter)?;

    // Execute the insert
    stmt.execute([name, email])?;

    // Get the last inserted row ID
    conn.last_insert_rowid()
}
```

### Notes:

- This function assumes the `users` table has columns `id`, `name`, and `email`, with `id` being the primary key and auto-incrementing.
- It uses `?` for error propagation, which is idiomatic in Rust when working with `rusqlite`.
- It uses `get()` on the `HashMap` to retrieve values, and returns an error if the required fields are missing.
- `last_insert_rowid()` is used to get the ID of the newly inserted row.

### Example usage:

```rust
use std::collections::HashMap;

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let conn = Connection::open_in_memory()?;
    conn.execute("CREATE TABLE users (id INTEGER PRIMARY KEY, name TEXT, email TEXT)", [])?;

    let mut form = HashMap::new();
    form.insert("name".to_string(), "Alice".to_string());
    form.insert("email".to_string(), "alice@example.com".to_string());

    let user_id = create_user_from_form(&conn, &form)?;
    println!("New user ID: {}", user_id);

    Ok(())
}
```

