use rusqlite::{Connection, Result, Statement};
use std::collections::HashMap;

pub fn get_sorted_products(conn: &Connection, sort_by: &str) -> Result<Vec<HashMap<String, String>>> {
    let mut stmt: Statement;

    // Determine the SQL query based on the sort_by parameter
    match sort_by {
        "name" => {
            stmt = conn.prepare("SELECT name, price, created_at FROM products ORDER BY name")?;
        }
        "price" => {
            stmt = conn.prepare("SELECT name, price, created_at FROM products ORDER BY price")?;
        }
        "created_at" => {
            stmt = conn.prepare("SELECT name, price, created_at FROM products ORDER BY created_at")?;
        }
        _ => {
            return Err(rusqlite::Error::InvalidQuery("Invalid sort parameter".to_string()));
        }
    }

    let mut rows = stmt.query([])?;
    let mut products = Vec::new();

    while let Some(row) = rows.next()? {
        let name: String = row.get(0)?;
        let price: String = row.get(1)?;
        let created_at: String = row.get(2)?;

        let mut product = HashMap::new();
        product.insert("name".to_string(), name);
        product.insert("price".to_string(), price);
        product.insert("created_at".to_string(), created_at);

        products.push(product);
    }

    Ok(products)
}
