### ✅ Helper Function in Rust

```rust
use actix_web::{web, Error};
use rusqlite::{Connection, Result, Row};
use std::borrow::Cow;

// Define a User struct that matches your database schema
#[derive(Debug, Clone)]
pub struct User {
    pub id: i32,
    pub email: String,
    pub password_hash: String,
}

// Helper function to fetch a user by email
pub fn get_user_by_email(conn: &Connection, email: &str) -> Result<Option<User>> {
    let mut stmt = conn.prepare("SELECT id, email, password_hash FROM users WHERE email = ?")?;
    let mut rows = stmt.query_named([("email", email)])?;

    if let Some(row) = rows.next()? {
        Ok(Some(User {
            id: row.get("id")?,
            email: row.get("email")?,
            password_hash: row.get("password_hash")?,
        }))
    } else {
        Ok(None)
    }
}
```

