### 📌 Usage in an Actix Web Handler

Here's how you might use this helper in an Actix Web handler:

```rust
use actix_web::{web, HttpResponse, Error};
use std::sync::Mutex;
use rusqlite::Connection;

// Assume this is initialized somewhere (e.g., in main or a module)
lazy_static::lazy_static! {
    static ref DB: Mutex<Connection> = Mutex::new(Connection::open_in_memory().unwrap());
}

// Example handler
pub async fn login_handler(web::Path(email): web::Path<String>) -> Result<HttpResponse, Error> {
    let conn = DB.lock().unwrap();

    match get_user_by_email(&conn, &email) {
        Ok(Some(user)) => {
            // User found, proceed with login logic
            Ok(HttpResponse::Ok().json(user))
        }
        Ok(None) => {
            // User not found
            Ok(HttpResponse::NotFound().json("User not found"))
        }
        Err(e) => {
            eprintln!("Database error: {}", e);
            Ok(HttpResponse::InternalServerError().json("Internal server error"))
        }
    }
