use rusqlite::{Connection, Result};
use std::borrow::Cow;

pub fn get_user_by_email(conn: &Connection, email: &str) -> Result<Option<(String, String)>> {
    // Query the users table for the user with the given email
    let mut stmt = conn.prepare("SELECT username, password FROM users WHERE email = ?")?;
    let mut rows = stmt.query_named([("email", Cow::Borrowed(email))])?;

    // We expect at most one row
    if let Some(row) = rows.next()? {
        Ok(Some((row.get(0)?, row.get(1)?)))
    } else {
        Ok(None)
    }
}
```

### Notes:
- This function returns an `Option<(String, String)>` containing the `username` and `password` if a user with the given email is found.
- It uses `rusqlite::Connection` and `rusqlite::Result` for error handling.
- It uses `query_named` for clarity and safety with parameter binding.
- You can adjust the fields returned (e.g., `id`, `created_at`, etc.) depending on your table schema.

### Usage example:

```rust
