use std::borrow::Cow;

pub fn get_user_by_email(conn: &Connection, email: &str) -> Result<Option<(String, String)>> {
    // Query the users table for the user with the given email
    let mut stmt = conn.prepare("SELECT username, password FROM users WHERE email = ?")?;
    let mut rows = stmt.query([&email])?;

    // Since we're only expecting one row, we can just take the first one
    if let Some(row) = rows.next()? {
        Ok(Some((row.get(0)?, row.get(1)?)))
    } else {
        Ok(None)
    }
}

let conn = Connection::open_in_memory()?;
let user = get_user_by_email(&conn, "user@example.com")?;
match user {
    Some((username, password)) => println!("Found user: {} with password {}", username, password),
    None => println!("User not found"),
}
